import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;

public class SecureCommandExecution {

    public static void main(String[] args) {
        try {
            BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
            System.out.print("Enter a command to execute: ");
            String userInput = br.readLine();

            // Sanitize and validate user input before executing any command
            if (!userInput.matches("[a-zA-Z0-9]+")) {
                System.out.println("Invalid input. Only alphanumeric characters are allowed.");
                return;
            }

            // Execute the command safely using ProcessBuilder
            ProcessBuilder pb = new ProcessBuilder("ping", userInput);
            Process process = pb.start();

            // Read and print the output of the executed command
            BufferedReader reader = new BufferedReader(new InputStreamReader(process.getInputStream()));
            String line;
            while ((line = reader.readLine()) != null) {
                System.out.println(line);
            }

        } catch (IOException e) {
            e.printStackTrace();
        }
    }
}

